// Count from 0 to 4
for (let i = 0; i < 5; i++) {
  console.log(i);
}

// Count by 2s from 0 to 10
console.log("Count by 2s:");
for (let i = 0; i <= 10; i += 2) {
  console.log(i);
}

// Count backwards from 5 to 1
console.log("Countdown:");
for (let i = 5; i >= 1; i--) {
  console.log(i);
}

